  1	/**
  2	 * Modal component for setting up scans with options for deep scans and concurrency.
  3	 * Allows specifying products for deep scanning and custom directories. Uses PatternFly for UI elements.
  4	 *
  5	 * @module sourcesScanModal
  6	 */
  7	import React, { useState } from 'react';
  8	import {
  9	  ActionGroup,
 10	  Button,
 11	  Checkbox,
 12	  Form,
 13	  FormContextProvider,
 14	  FormGroup,
 15	  HelperText,
 16	  Modal,
 17	  ModalVariant,
 18	  NumberInput,
 19	  TextArea,
 20	  TextInput
 21	} from '@patternfly/react-core';
 22	import { helpers } from '../../helpers';
 23	import { type Scan, type SourceType } from '../../types/types';
 24	
 25	interface AddSourcesScanModalProps {
 26	  isOpen: boolean;
 27	  sources?: SourceType[];
 28	  onClose?: () => void;
 29	  onSubmit?: (payload: Scan) => Promise<void>;
 30	}
 31	
 32	const AddSourcesScanModal: React.FC<AddSourcesScanModalProps> = ({
 33	  isOpen,
 34	  sources,
 35	  onClose = Function.prototype,
 36	  onSubmit = Function.prototype
 37	}) => {
 38	  const [deepScans, setDeepScans] = useState<string[]>([]);
 39	
 40	  const onCloseModal = () => {
 41	    setDeepScans([]);
 42	    onClose();
 43	  };
 44	
 45	  const onDeepScanChange = (option, checked) => {
 46	    if (checked) {
 47	      setDeepScans([...deepScans, option]);
 48	    } else {
 49	      setDeepScans(deepScans.filter(o => o !== option));
 50	    }
 51	  };
 52	
 53	  const onScan = values => {
 54	    const payload = {
 55	      name: values['scan-name'],
 56	      sources: sources?.map(s => s.id),
 57	      options: {
 58	        max_concurrency: values['scan-max-concurrent'],
 59	        enabled_extended_product_search: {
 60	          jboss_eap: deepScans.includes('jboss_eap'),
 61	          jboss_fuse: deepScans.includes('jboss_fuse'),
 62	          jboss_ws: deepScans.includes('jboss_ws'),
 63	          search_directories: helpers.normalizeCommaSeparated(values['scan-alt-scan'])
 64	        }
 65	      }
 66	    };
 67	    onSubmit(payload).finally(() => {
 68	      setDeepScans([]);
 69	    });
 70	  };
 71	
 72	  return (
 73	    <Modal variant={ModalVariant.small} title="Scan" isOpen={isOpen} onClose={() => onCloseModal()}>
 74	      <FormContextProvider
 75	        initialValues={{
 76	          'scan-sources': sources?.map(s => s.name).join(', ') || '',
 77	          'scan-max-concurrent': '25'
 78	        }}
 79	      >
 80	        {({ setValue, getValue, values }) => (
 81	          <Form>
 82	            <FormGroup label="Name" isRequired fieldId="scan-name">
 83	              <TextInput
 84	                value={getValue('scan-name')}
 85	                placeholder="Enter a name for the scan."
 86	                isRequired
 87	                type="text"
 88	                id="scan-name"
 89	                name="scan-name"
 90	                onChange={ev => {
 91	                  setValue('scan-name', (ev.target as HTMLInputElement).value);
 92	                }}
 93	                ouiaId="name"
 94	              />
 95	            </FormGroup>
 96	            <FormGroup label="Sources" isRequired fieldId="scan-sources">
 97	              <TextArea value={getValue('scan-sources')} isDisabled isRequired id="scan-sources" name="scan-sources" />
 98	            </FormGroup>
 99	            <FormGroup label="Maximum concurrent scans" fieldId="scan-max-concurrent">
100	              <NumberInput
101	                value={Number(getValue('scan-max-concurrent'))}
102	                onMinus={() =>
103	                  setValue('scan-max-concurrent', '' + Math.max(1, Number(getValue('scan-max-concurrent')) - 1))
104	                }
105	                onChange={ev =>
106	                  setValue(
107	                    'scan-max-concurrent',
108	                    '' + Math.max(1, Math.min(200, Number((ev.target as HTMLInputElement).value)))
109	                  )
110	                }
111	                onPlus={() =>
112	                  setValue('scan-max-concurrent', '' + Math.min(200, Number(getValue('scan-max-concurrent')) + 1))
113	                }
114	                inputName="input"
115	                inputAriaLabel="number input"
116	                minusBtnAriaLabel="minus"
117	                plusBtnAriaLabel="plus"
118	                data-ouia-component-id="scan_concurrency"
119	              />
120	            </FormGroup>
121	            <FormGroup
122	              label="Deep scan for these products"
123	              isStack
124	              fieldId="scan-deep-scan"
125	              hasNoPaddingTop
126	              role="group"
127	            >
128	              {[
129	                { label: 'JBoss EAP', value: 'jboss_eap' },
130	                { label: 'Fuse', value: 'jboss_fuse' },
131	                { label: 'JBoss web server', value: 'jboss_ws' }
132	              ].map(o => (
133	                <Checkbox
134	                  key={`deep-scan-${o.value}`}
135	                  label={o.label}
136	                  id={`deep-scan-${o.value}`}
137	                  isChecked={deepScans.includes(o.value)}
138	                  onChange={(_ev, ch) => onDeepScanChange(o.value, ch)}
139	                  ouiaId={`options_${o.value}`}
140	                />
141	              ))}
142	            </FormGroup>
143	            {!!deepScans.length && (
144	              <FormGroup label="Scan alternate directories" fieldId="scan-alt-scan">
145	                <TextArea
146	                  value={getValue('scan-alt-scan')}
147	                  onChange={(_ev, val) => setValue('scan-alt-scan', val)}
148	                  id="scan-alt-scan"
149	                  name="scan-alt-scan"
150	                  data-ouia-component-id="scan_alt_dirs"
151	                />
152	                <HelperText>Default: directories are /./opt./app./home/usr</HelperText>
153	              </FormGroup>
154	            )}
155	            <ActionGroup>
156	              <Button variant="primary" onClick={() => onScan({ ...values, deepScans })}>
157	                Save
158	              </Button>
159	              <Button variant="link" onClick={() => onCloseModal()}>
160	                Cancel
161	              </Button>
162	            </ActionGroup>
163	          </Form>
164	        )}
165	      </FormContextProvider>
166	    </Modal>
167	  );
168	};
169	
170	export { AddSourcesScanModal as default, AddSourcesScanModal, type AddSourcesScanModalProps };

